@page
@model IndexModel
@{
    ViewData["Title"] = "SAML AuthnRequest Generator";
}

<div class="text-center">
    <h1 class="display-4">SAML AuthnRequest Generator</h1>
    <p>Generates a SAML 2.0 AuthnRequest, signs it with RSA-SHA1, and optionally encrypts the Issuer with 3DES.</p>
</div>

<div class="container mt-5">
    <form method="post" asp-page-handler="Generate">
        <div class="form-group row mb-3">
            <label asp-for="SpEntityId" class="col-sm-3 col-form-label">SP Entity ID:</label>
            <div class="col-sm-9">
                <input asp-for="SpEntityId" class="form-control" />
            </div>
        </div>
        <div class="form-group row mb-3">
            <label asp-for="AssertionConsumerServiceUrl" class="col-sm-3 col-form-label">Assertion Consumer Service URL:</label>
            <div class="col-sm-9">
                <input asp-for="AssertionConsumerServiceUrl" class="form-control" />
            </div>
        </div>
        <div class="form-group row mb-3">
            <div class="col-sm-3"></div>
            <div class="col-sm-9">
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" asp-for="EncryptIssuer" />
                    <label class="form-check-label" asp-for="EncryptIssuer">
                        Encrypt Issuer Element (using IdP's public key for key transport, 3DES for content)
                    </label>
                </div>
            </div>
        </div>
        <div class="form-group row mb-3">
            <div class="col-sm-12 text-center">
                <button type="submit" class="btn btn-primary">Generate SAML AuthnRequest</button>
            </div>
        </div>
    </form>

    @if (!string.IsNullOrEmpty(Model.SamlRequestXml))
    {
        <h2 class="mt-5">Generated SAML AuthnRequest XML:</h2>
        <pre class="bg-light p-3 border rounded text-start" style="max-height: 600px; overflow: auto;"><code>@Html.Raw(Model.SamlRequestXml)</code></pre>

        <h2 class="mt-5">Base64 Encoded (for HTTP-Redirect/POST binding):</h2>
        <pre class="bg-light p-3 border rounded text-start"><code>@Convert.ToBase64String(System.Text.Encoding.UTF8.GetBytes(Model.SamlRequestXml))</code></pre>
    }
</div>

// File: Pages/Index.cshtml.cs
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.RazorPages;
using SamlRequestGenerator.Services;
using System.Text; // For Base64 encoding in the view, not directly used here
using System.Xml; // For XmlDocument related string escapes, though System.Security.SecurityElement.Escape is used

namespace SamlRequestGenerator.Pages
{
    public class IndexModel : PageModel
    {
        private readonly ILogger<IndexModel> _logger;
        private readonly SamlAuthnRequestService _samlService;

        public IndexModel(ILogger<IndexModel> logger, SamlAuthnRequestService samlService)
        {
            _logger = logger;
            _samlService = samlService;
        }

        [BindProperty]
        public string SpEntityId { get; set; } = "https://sp.example.com/saml";

        [BindProperty]
        public string AssertionConsumerServiceUrl { get; set; } = "https://sp.example.com/saml/acs";

        [BindProperty]
        public bool EncryptIssuer { get; set; } = false;

        public string SamlRequestXml { get; set; }

        public void OnGet()
        {
            // Initial page load
        }

        public IActionResult OnPostGenerate()
        {
            try
            {
                SamlRequestXml = _samlService.GenerateSignedAndEncryptedAuthnRequest(
                    SpEntityId,
                    AssertionConsumerServiceUrl,
                    EncryptIssuer);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error generating SAML AuthnRequest.");
                // Escape potential XML characters in the error message for safe display
                SamlRequestXml = $"<Error>{System.Security.SecurityElement.Escape(ex.Message)}</Error>";
            }
            return Page();
        }
    }
}

