using System;
using System.IO;
using System.Security.Cryptography;
using System.Security.Cryptography.X509Certificates;
using System.Security.Cryptography.Xml;
using System.Text;
using System.Xml;

namespace SamlRequestGenerator.Services
{
    public class SamlAuthnRequestService
    {
        // SAML Namespaces
        private const string SamlProtocolNamespace = "urn:oasis:names:tc:SAML:2.0:protocol";
        private const string SamlAssertionNamespace = "urn:oasis:names:tc:SAML:2.0:assertion";
        private const string XmlDsigNamespace = "http://www.w3.org/2000/09/xmldsig#";
        private const string XmlEncNamespace = "http://www.w3.org/2001/04/xmlenc#";

        // Signing Algorithms (legacy compatibility as requested)
        private const string SignatureMethodRsaSha1 = "http://www.w3.org/2000/09/xmldsig#rsa-sha1";
        private const string DigestMethodSha1 = "http://www.w3.org/2000/09/xmldsig#sha1";

        // Encryption Algorithms (legacy compatibility as requested, 3DES preferred)
        private const string EncryptionMethodTripleDes = "http://www.w3.org/2001/04/xmlenc#tripledes-cbc";
        private const string KeyTransportMethodRsaPkcs1v15 = "http://www.w3.org/2001/04/xmlenc#rsa-1_5"; // RSA-PKCS1-v1_5 for key transport (legacy compatible)

        private readonly X509Certificate2 _spSigningCert;
        private readonly X509Certificate2 _idPEncryptionCert; // IdP's public key for encrypting symmetric keys

        public SamlAuthnRequestService()
        {
            // For demonstration purposes, generate self-signed certificates in memory.
            // In a real application, you would load these from files (PFX/CER) or certificate stores.

            _spSigningCert = GenerateSelfSignedCertificate("CN=Test SAML SP", "sp_key_password", true);
            _idPEncryptionCert = GenerateSelfSignedCertificate("CN=Test SAML IdP", "idp_key_password", false); // We only need IdP's public key for encryption

            // Ensure private keys are available for signing
            if (!_spSigningCert.HasPrivateKey)
            {
                throw new CryptographicException("SP signing certificate must have a private key.");
            }
        }

        /// <summary>
        /// Generates a self-signed X.509 certificate for demonstration.
        /// </summary>
        /// <param name="subjectName">The subject distinguished name for the certificate.</param>
        /// <param name="password">The password to protect the private key if exported.</param>
        /// <param name="privateKeyExportable">Whether the private key should be exportable.</param>
        /// <returns>A new X509Certificate2 instance.</returns>
        private X509Certificate2 GenerateSelfSignedCertificate(string subjectName, string password, bool privateKeyExportable)
        {
            using (RSA rsa = RSA.Create(2048)) // 2048-bit key for RSA
            {
                var request = new CertificateRequest(
                    subjectName,
                    rsa,
                    HashAlgorithmName.SHA256, // Hashing algorithm for the certificate itself
                    RSASignaturePadding.Pkcs1);

                request.CertificateExtensions.Add(
                    new X509KeyUsageExtension(
                        X509KeyUsageFlags.DigitalSignature | X509KeyUsageFlags.KeyEncipherment, // DigitalSignature for XML signing, KeyEncipherment for encrypting symmetric keys
                        critical: true));

                var sanBuilder = new SubjectAlternativeNameBuilder();
                sanBuilder.AddDnsName("localhost");
                sanBuilder.AddDnsName("127.0.0.1");
                request.CertificateExtensions.Add(sanBuilder.Build());

                DateTimeOffset now = DateTimeOffset.UtcNow;
                var cert = request.CreateSelfSigned(now.AddDays(-1), now.AddYears(5)); // Valid for 5 years

                // Export to PFX with password to ensure private key is retained and mark it exportable.
                // Then load from the PFX to get the proper X509Certificate2 object including private key.
                byte[] pfxBytes = cert.Export(X509ContentType.Pfx, password);
                var loadedCert = new X509Certificate2(pfxBytes, password, privateKeyExportable ? X509KeyStorageFlags.Exportable : X509KeyStorageFlags.DefaultKeySet);

                return loadedCert;
            }
        }

        /// <summary>
        /// Generates, signs, and optionally encrypts a SAML AuthnRequest XML document.
        /// </summary>
        /// <param name="spEntityId">The Entity ID of the Service Provider.</param>
        /// <param name="assertionConsumerServiceUrl">The URL where the IdP should send the SAML Response.</param>
        /// <param name="encryptIssuer">Whether to encrypt the Issuer element.</param>
        /// <returns>The signed and optionally encrypted SAML AuthnRequest XML as a string.</returns>
        public string GenerateSignedAndEncryptedAuthnRequest(
            string spEntityId,
            string assertionConsumerServiceUrl,
            bool encryptIssuer = false)
        {
            // 1. Create the AuthnRequest XML
            XmlDocument samlDocument = CreateAuthnRequest(spEntityId, assertionConsumerServiceUrl);

            // 2. Encrypt sensitive attributes if requested (e.g., the Issuer element)
            if (encryptIssuer)
            {
                EncryptIssuerElement(samlDocument, _idPEncryptionCert);
            }

            // 3. Sign the XML document
            SignXml(samlDocument, _spSigningCert);

            // Output the XML
            return FormatXml(samlDocument);
        }

        private XmlDocument CreateAuthnRequest(string spEntityId, string assertionConsumerServiceUrl)
        {
            var doc = new XmlDocument();
            doc.PreserveWhitespace = true; // Important for signing and encryption to maintain integrity

            // Create AuthnRequest root element
            XmlElement authnRequest = doc.CreateElement("samlp", "AuthnRequest", SamlProtocolNamespace);
            doc.AppendChild(authnRequest);

            authnRequest.SetAttribute("ID", "_" + Guid.NewGuid().ToString("N")); // SAML IDs usually start with an underscore
            authnRequest.SetAttribute("Version", "2.0");
            authnRequest.SetAttribute("IssueInstant", DateTime.UtcNow.ToString("yyyy-MM-ddTHH:mm:ss.fffZ")); // UTC format with milliseconds
            authnRequest.SetAttribute("ProtocolBinding", "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"); // Common binding
            authnRequest.SetAttribute("AssertionConsumerServiceURL", assertionConsumerServiceUrl);

            // Create Issuer element
            XmlElement issuer = doc.CreateElement("saml", "Issuer", SamlAssertionNamespace);
            issuer.InnerText = spEntityId;
            authnRequest.AppendChild(issuer);

            // Create NameIDPolicy element
            XmlElement nameIdPolicy = doc.CreateElement("samlp", "NameIDPolicy", SamlProtocolNamespace);
            nameIdPolicy.SetAttribute("Format", "urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified"); // Common format
            nameIdPolicy.SetAttribute("AllowCreate", "true");
            authnRequest.AppendChild(nameIdPolicy);

            return doc;
        }

        private void SignXml(XmlDocument doc, X509Certificate2 signingCert)
        {
            if (signingCert == null || !signingCert.HasPrivateKey)
            {
                throw new ArgumentException("Signing certificate must be provided and contain a private key.");
            }

            // Create a SignedXml object
            SignedXml signedXml = new SignedXml(doc);

            // Set the key for signing (GetRSAPrivateKey is .NET Core specific)
            signedXml.SigningKey = signingCert.GetRSAPrivateKey();

            // Set the signature method (RSA-SHA1 for legacy compatibility)
            signedXml.SignatureMethod = SignatureMethodRsaSha1;

            // Create a Reference to the document itself
            Reference reference = new Reference();
            reference.Uri = ""; // Sign the entire document
            reference.AddTransform(new XmlDsigEnvelopedSignatureTransform()); // Enveloped signature
            reference.AddTransform(new XmlDsigC14NTransform()); // Canonicalization
            reference.DigestMethod = DigestMethodSha1; // Set the digest method (SHA-1 for legacy compatibility)

            signedXml.AddReference(reference);

            // Add the KeyInfo for the certificate (public key part)
            KeyInfo keyInfo = new KeyInfo();
            keyInfo.AddClause(new KeyInfoX509Data(signingCert));
            signedXml.KeyInfo = keyInfo;

            // Compute the signature
            signedXml.ComputeSignature();

            // Append the signature to the document
            XmlElement signatureElement = signedXml.GetXml();
            doc.DocumentElement.AppendChild(signatureElement);
        }

        private void EncryptIssuerElement(XmlDocument doc, X509Certificate2 idPEncryptionCert)
        {
            if (idPEncryptionCert == null || idPEncryptionCert.PublicKey.Oid.Value != "1.2.840.113549.1.1.1") // OID for RSA public key
            {
                throw new ArgumentException("IdP encryption certificate must be provided and contain an RSA public key.");
            }

            // Select the Issuer element using NamespaceManager
            XmlNamespaceManager nsmgr = GetNamespaceManager(doc);
            XmlElement issuerElement = (XmlElement)doc.DocumentElement.SelectSingleNode($"//saml:Issuer", nsmgr);
            if (issuerElement == null)
            {
                throw new InvalidOperationException("Issuer element not found for encryption.");
            }

            // 1. Generate a symmetric key (TripleDES)
            using (TripleDES tripleDes = TripleDES.Create())
            {
                tripleDes.GenerateKey();
                tripleDes.Mode = CipherMode.CBC; // CBC is standard for XML encryption
                tripleDes.Padding = PaddingMode.PKCS7; // PKCS7 is commonly used

                // Create a new EncryptedXml object
                EncryptedXml encryptedXml = new EncryptedXml(doc);

                // 2. Encrypt the Issuer element
                byte[] encryptedElementBytes = encryptedXml.EncryptData(issuerElement, tripleDes, false);

                // Create EncryptedData element
                EncryptedData encryptedData = new EncryptedData();
                encryptedData.Type = EncryptedXml.XmlEncElementUrl; // Encrypting an element
                encryptedData.EncryptionMethod = new EncryptionMethod(EncryptionMethodTripleDes);

                // Add the encrypted data (ciphertext)
                encryptedData.CipherData.CipherValue = encryptedElementBytes;

                // 3. Encrypt the symmetric key (TripleDES key) using the IdP's public key (RSA)
                encryptedData.KeyInfo = new KeyInfo();

                EncryptedKey encryptedKey = new EncryptedKey();
                encryptedKey.EncryptionMethod = new EncryptionMethod(KeyTransportMethodRsaPkcs1v15); // Use RSA-PKCS1-v1_5 for key transport (legacy compatible)

                // Encrypt the symmetric key with IdP's public key
                byte[] encryptedSymmetricKey = EncryptedXml.EncryptKey(tripleDes.Key, idPEncryptionCert.GetRSAPublicKey(), false);
                encryptedKey.CipherData.CipherValue = encryptedSymmetricKey;

                // Add KeyInfoX509Data for the IdP's public certificate to help the IdP identify the key to use for decryption
                KeyInfoX509Data keyInfoX509Data = new KeyInfoX509Data(idPEncryptionCert);
                encryptedKey.KeyInfo.AddClause(keyInfoX509Data);

                // Link the EncryptedKey to the EncryptedData
                DataReference dataReference = new DataReference();
                string encryptedDataId = "EncData_" + Guid.NewGuid().ToString("N");
                encryptedData.Id = encryptedDataId; // Assign an ID to the EncryptedData
                dataReference.Uri = "#" + encryptedDataId; // Reference the EncryptedData by its ID
                encryptedKey.AddReference(dataReference);

                encryptedData.KeyInfo.AddClause(new KeyInfoEncryptedKey(encryptedKey));

                // Replace the original Issuer element with the EncryptedData element
                EncryptedXml.ReplaceElement(issuerElement, encryptedData, false);
            }
        }

        private XmlNamespaceManager GetNamespaceManager(XmlDocument doc)
        {
            var nsmgr = new XmlNamespaceManager(doc.NameTable);
            nsmgr.AddNamespace("samlp", SamlProtocolNamespace);
            nsmgr.AddNamespace("saml", SamlAssertionNamespace);
            nsmgr.AddNamespace("ds", XmlDsigNamespace);
            nsmgr.AddNamespace("enc", XmlEncNamespace);
            return nsmgr;
        }

        private string FormatXml(XmlDocument doc)
        {
            using (var stringWriter = new StringWriter())
            using (var xmlTextWriter = new XmlTextWriter(stringWriter))
            {
                xmlTextWriter.Formatting = Formatting.Indented;
                doc.WriteTo(xmlTextWriter);
                return stringWriter.ToString();
            }
        }
    }
}